fn solve(nums: Vec<i64>) -> Vec<i64> {
    let n = nums.len();
    let mut ans = Vec::with_capacity(2 * n);

    // Copy the first n elements
    for i in 0..n {
        ans.push(nums[i]);
    }

    // Fill the last n elements with the reverse of nums
    for i in 0..n {
        // ans[i + n] corresponds to nums[n - 1 - i] in the logic.
        // Since we are pushing to ans, the index will be n + i.
        // We want the element from nums that is at index n - 1 - i in reverse.
        ans.push(nums[n - 1 - i]);
    }

    ans
}

